const items = $input.all(); const http = this.helpers.httpRequest; const GKEY = $env.GEMINI_API_KEY; const out = [];
const MAX_PAR_RUN = 18;
const clean = n => (n || '').replace(/\s*\([^)]*\)\s*/g, ' ').replace(/—.*$/, '').replace(/\s+/g, ' ').trim();
// On ne garde que les cibles SANS page LinkedIn, plafonnées pour rester sous le timeout 300s
const todo = items.filter(it => { const f = it.json; return (f.Entreprise || '').toString().trim() && !((f['Page LinkedIn entreprise'] || '').toString().trim()); }).slice(0, MAX_PAR_RUN);
for (const it of todo) {
  const f = it.json; const id = f.id; const company = (f.Entreprise || '').toString().trim();
  if (!company || !id) continue;
  const c = clean(company); let url = '';
  try {
    if (GKEY) {
      const prompt = "Quelle est l'URL exacte de la page LinkedIn officielle de l'entreprise « " + c + " » en France ? Réponds UNIQUEMENT par l'URL au format https://www.linkedin.com/company/... Si tu n'es pas certain à 100%, réponds exactement: AUCUNE. Aucun autre texte.";
      const r = await http({ method: 'POST', url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + encodeURIComponent(GKEY), body: { contents: [{ parts: [{ text: prompt }] }], tools: [{ google_search: {} }], generationConfig: { temperature: 0 } }, json: true, timeout: 12000 });
      const parts = (r && r.candidates && r.candidates[0] && r.candidates[0].content && r.candidates[0].content.parts) || [];
      const txt = parts.map(p => p.text || '').join(' ');
      const m = txt.match(/https?:\/\/[a-z.]*linkedin\.com\/company\/[^\s)]+/i);
      if (m) url = m[0].replace(/[).,]+$/, '').replace(/\/$/, '');
    }
  } catch (e) { url = ''; }
  if (url) out.push({ json: { id: id, 'Page LinkedIn entreprise': url } });
}
return out;
